import json
from collections import defaultdict

records = [
    {"id": "V-001", "name": "Pfizer Inc", "city": "New York"},
    {"id": "V-002", "name": "Novartis Pharma AG", "city": "Basel"},
    {"id": "V-003", "name": "Mystery Supplier", "city": ""},
    {"id": "V-004", "name": "3M Healthcare", "city": "St Paul"}
]

entities = [
    {"id": "E-100", "name": "Pfizer Inc."},
    {"id": "E-200", "name": "Novartis AG"},
    {"id": "E-300", "name": "3M Company"}
]

symbol_table = "\n".join(f"  {e['id']}: {e['name']}" for e in entities)

# Phase 1: Triage
triage_prompts = [
    f"Triage this record against known entities. Return JSON with: record_id, disposition (exact_match|fuzzy_match|needs_context|anomaly|skip), confidence (0-1), rationale, matched_entity_id (null if no match).\nEntities:\n{symbol_table}\nRecord: {json.dumps(r)}"
    for r in records
]
raw_triage = llm_query_batched(triage_prompts)

decisions = []
for raw in raw_triage:
    cleaned = raw.strip()
    if cleaned.startswith("```"):
        cleaned = cleaned.split("\n", 1)[-1].rsplit("```", 1)[0].strip()
    decisions.append(json.loads(cleaned))

# Bucket by disposition
buckets = defaultdict(list)
for d in decisions:
    buckets[d["disposition"]].append(d)

print("Disposition distribution:")
for disp, items in sorted(buckets.items()):
    print(f"  {disp}: {len(items)}")

# Phase 2: Route fuzzy matches to comparison agent
routed_results = {}
if "exact_match" in buckets:
    routed_results["exact_match"] = [
        {"record_id": d["record_id"], "matched_to": d["matched_entity_id"], "action": "COMMIT"}
        for d in buckets["exact_match"]
    ]

if "fuzzy_match" in buckets:
    comparison_prompts = [
        f"Compare record {d['record_id']} to entity {d['matched_entity_id']}. "
        f"Return JSON: record_id, entity_id, field_agreements (list), field_disagreements (list of dicts with field/record_val/entity_val), recommendation (ACCEPT|REJECT|HUMAN_REVIEW), revised_confidence (0-1)."
        for d in buckets["fuzzy_match"]
    ]
    raw_comparisons = llm_query_batched(comparison_prompts)
    routed_results["fuzzy_match"] = [json.loads(r.strip()) for r in raw_comparisons]

if "needs_context" in buckets:
    routed_results["needs_context"] = [
        {"record_id": d["record_id"], "action": "ENQUEUE_FOR_ENRICHMENT"}
        for d in buckets["needs_context"]
    ]

if "anomaly" in buckets:
    routed_results["anomaly"] = [
        {"record_id": d["record_id"], "action": "QUARANTINE"}
        for d in buckets["anomaly"]
    ]

for route, items in routed_results.items():
    print(f"Route [{route}]: {len(items)} items")
    for item in items:
        print(f"  {item}")
